UPDATE ASSIGNMENT
   SET DELETE_YN = 1,
       DELETE_AT = SYSDATE,
       UPDATED_AT = SYSDATE
 WHERE ASSIGN_ID = #{assignmentId}
   AND CLASS_ID = #{classId}
   AND TEACHER_ID = #{teacherId}

UPDATE ASSIGNMENT
   SET DELETE_YN = 0,
       DELETE_AT = TO_DATE('9999-12-31 23:59', 'YYYY-MM-DD HH24:MI'),
       UPDATED_AT = SYSDATE
 WHERE ASSIGN_ID = #{assignmentId}
   AND CLASS_ID = #{classId}
   AND TEACHER_ID = #{teacherId}

