SELECT NVL(A.UPLOADPATH, '')
  FROM ATTACH A
 WHERE A.PNO IN (
       SELECT S.SUB_ID
         FROM ASSIGN_SUB S
        WHERE S.ASSIGN_ID = #{assignmentId}
          AND S.STUDENT_ID IN (
              SELECT SC.STUDENT_ID
                FROM STUDENT_CLASS SC
               WHERE SC.CLASS_ID = #{classId}
          )
 )

