UPDATE ASSIGN_SUB
   SET RETURN_REASON = #{returnReason, jdbcType=CLOB},
       SUBMIT_STATUS = 'RETURNED',
       UPDATED_AT = SYSDATE
 WHERE SUB_ID = #{subId}
   AND ASSIGN_ID = #{assignmentId}
   AND STUDENT_ID = #{studentId}

UPDATE ASSIGN_SUB
   SET RETURN_REASON = NULL,
       SUBMIT_STATUS = 'FEEDBACK_COMPLETED',
       UPDATED_AT = SYSDATE
 WHERE SUB_ID = #{subId}
   AND ASSIGN_ID = #{assignmentId}
   AND STUDENT_ID = #{studentId}

